\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 Uncollapses all folder tracks at the same depth as the shallowest selected track.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
